SET search_path TO public;

-- ============================================================
-- TORQUED — Migration 064: vehicle_models backfill from fleet_vehicles
-- The "Confirm your exact variant" picker (/api/vehicles/lookup) reads only
-- vehicle_models; entire makes (Land Rover, Volvo, Jaguar, BYD, MG, Tesla,
-- Chery, LDV, Daihatsu, GWM...) existed only in fleet_vehicles, so the picker
-- returned nothing for them. This backfills one vehicle_models row per
-- uncovered fleet vehicle (engine size/timing from its engine family).
-- Applied directly to production 2026-07-21 (data-only).
-- ============================================================

ON CONFLICT (make, model, submodel, chassis_code, engine_code, year_from) DO NOTHING;
